namespace CheckoutWizard;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

public interface IAddressValidator
{
    Task<bool> ValidateAddressAsync(string address, string city, string zip, CancellationToken ct);
}

@namespace CheckoutWizard

<div class="checkout-wizard">
    <h2>Checkout</h2>

    <div class="step-indicator">
        Step @(_step + 1) of 2
    </div>

    @if (_step == 0)
    {
        <ShippingStep Shipping="_order.Shipping" OnNext="HandleShippingComplete" />
    }
    else
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="HandleBack"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    /// <summary>Raised when the user clicks "Place Order" with a completed order.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order _order = new();
    private int _step;

    private void HandleShippingComplete()
    {
        _step = 1;
    }

    private void HandleBack()
    {
        _step = 0;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace CheckoutWizard
@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <div class="form-group">
        <label for="name">Name</label>
        <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error" role="alert">@_errorMessage</div>
}

<button class="btn-next" disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    private async Task ValidateAndProceed()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(Shipping.Name) ||
            string.IsNullOrWhiteSpace(Shipping.Address) ||
            string.IsNullOrWhiteSpace(Shipping.City) ||
            string.IsNullOrWhiteSpace(Shipping.ZipCode))
        {
            _errorMessage = "All fields are required.";
            return;
        }

        // Cancel any in-flight validation (e.g. user went back and changed fields).
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was intentionally cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

@namespace CheckoutWizard

<fieldset>
    <legend>Payment Information</legend>

    <div class="form-group">
        <label for="card">Card Number</label>
        <input id="card" @bind="Payment.CardNumber" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="expiry">Expiry Date</label>
        <input id="expiry" placeholder="MM/YY" @bind="Payment.ExpiryDate" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error" role="alert">@_errorMessage</div>
}

<div class="button-group">
    <button class="btn-back" @onclick="OnBack">Back</button>
    <button class="btn-place-order" @onclick="HandlePlaceOrder">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback OnPlaceOrder { get; set; }

    private string? _errorMessage;

    private async Task HandlePlaceOrder()
    {
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(Payment.CardNumber) ||
            string.IsNullOrWhiteSpace(Payment.ExpiryDate))
        {
            _errorMessage = "All payment fields are required.";
            return;
        }

        await OnPlaceOrder.InvokeAsync();
    }
}

